import React, { useState, useEffect } from "react";
import axios from "axios";

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

const templates = {
  promo: {
    subject: "🌸 Ưu đãi đặc biệt từ DTP Flower Shop",
    html: `
      <h2 style="color:#d14b6a;">🎉 Ưu đãi đặc biệt!</h2>
      <p>Giảm <strong>20%</strong> cho tất cả sản phẩm hoa tươi trong tuần này.</p>
      <p>Đặt hoa ngay hôm nay để nhận ưu đãi hấp dẫn nhé! 💐</p>
    `,
  },
  holiday: {
    subject: "🎀 Quà tặng dịp lễ từ DTP Flower Shop",
    html: `
      <h2 style="color:#d14b6a;">🌸 Quà tặng ngày lễ!</h2>
      <p>DTP Flower Shop dành tặng bạn chương trình giảm giá hoa tươi cho các dịp lễ hội sắp tới.</p>
      <p>Hãy chọn những bó hoa xinh đẹp để gửi yêu thương đến người thân yêu. 💝</p>
    `,
  },
  custom: {
    subject: "",
    html: "",
  },
};

const SendEmailPage = () => {
  const [subject, setSubject] = useState("");
  const [group, setGroup] = useState("all");
  const [templateName, setTemplateName] = useState("promo");
  const [htmlContent, setHtmlContent] = useState(templates.promo.html);
  const [resultMsg, setResultMsg] = useState(null);
  const [loading, setLoading] = useState(false);

  // ===========================
  // 📌 Khi đổi template → auto điền nội dung
  // ===========================
  useEffect(() => {
    const tpl = templates[templateName];

    if (!tpl) return;

    // auto fill nội dung
    setHtmlContent(tpl.html);

    // nếu subject đang trống thì auto luôn
    if (!subject.trim() && tpl.subject) {
      setSubject(tpl.subject);
    }
    // nếu là custom thì giữ nguyên subject, cho bạn tự nhập
  }, [templateName]);

  // ===========================
  // 📌 GỬI EMAIL
  // ===========================
  const sendEmail = async () => {
    setResultMsg(null);

    if (!subject.trim()) {
      setResultMsg({
        type: "error",
        text: "❌ Bạn phải nhập tiêu đề email!",
      });
      return;
    }

    if (!htmlContent.trim()) {
      setResultMsg({
        type: "error",
        text: "❌ Nội dung email không được trống!",
      });
      return;
    }

    try {
      setLoading(true);

      const token = localStorage.getItem("token");
      if (!token) {
        setResultMsg({
          type: "error",
          text: "❌ Bạn chưa đăng nhập (không có token).",
        });
        setLoading(false);
        return;
      }

      console.log("Sending email payload:", {
        subject,
        group,
        html: htmlContent,
        templateName,
      });

      const res = await axios.post(
        `${API_URL}/api/email/send`,
        {
          subject,
          group,
          html: htmlContent,
          templateName,
        },
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );

      setResultMsg({
        type: "success",
        text: res.data.message || "📩 Gửi email thành công!",
      });
    } catch (err) {
      console.error("Frontend Email Error:", err);

      let msg = "❌ Không thể gửi email (frontend error).";
      if (err.response?.status === 401 || err.response?.status === 403) {
        msg = "❌ Bạn không có quyền gửi email (chưa đăng nhập / không phải admin).";
      }

      setResultMsg({
        type: "error",
        text: msg,
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: "40px" }}>
      <h1
        style={{
          fontSize: "28px",
          fontWeight: "700",
          color: "#d14b6a",
          marginBottom: "20px",
        }}
      >
        📩 Gửi Email Marketing
      </h1>

      {/* Layout A: Trái Form - Phải Preview */}
      <div
        style={{
          display: "flex",
          gap: "24px",
          alignItems: "flex-start",
        }}
      >
        {/* LEFT: FORM */}
        <div
          style={{
            flex: 1,
            background: "white",
            padding: "24px",
            borderRadius: "12px",
            boxShadow: "0 10px 40px rgba(0,0,0,0.05)",
          }}
        >
          {/* SUBJECT */}
          <label style={{ fontWeight: 600 }}>Tiêu đề Email</label>
          <input
            type="text"
            value={subject}
            onChange={(e) => setSubject(e.target.value)}
            placeholder="Nhập tiêu đề..."
            style={{
              width: "100%",
              marginTop: "8px",
              marginBottom: "20px",
              padding: "10px 12px",
              borderRadius: "8px",
              border: "1px solid #ddd",
            }}
          />

          {/* GROUP */}
          <label style={{ fontWeight: 600 }}>Gửi đến nhóm</label>
          <select
            value={group}
            onChange={(e) => setGroup(e.target.value)}
            style={{
              width: "100%",
              padding: "10px 12px",
              marginTop: "8px",
              marginBottom: "20px",
              borderRadius: "8px",
              border: "1px solid #ddd",
            }}
          >
            <option value="all">📢 Tất cả khách hàng</option>
            <option value="user">👤 Chỉ User bình thường</option>
            <option value="admin">🛠 Admin</option>
            <option value="newsletter">📬 Người đăng ký Newsletter</option>
            <option value="vip">💎 VIP (Chi ≥ 3.000.000)</option>
          </select>

          {/* TEMPLATE */}
          <label style={{ fontWeight: 600 }}>Mẫu email</label>
          <select
            value={templateName}
            onChange={(e) => setTemplateName(e.target.value)}
            style={{
              width: "100%",
              padding: "10px 12px",
              marginTop: "8px",
              marginBottom: "20px",
              borderRadius: "8px",
              border: "1px solid #ddd",
            }}
          >
            <option value="promo">🎁 Khuyến mãi</option>
            <option value="holiday">🎉 Dịp lễ</option>
            <option value="custom">📝 Tuỳ chỉnh</option>
          </select>

          {/* CUSTOM HTML */}
          {templateName === "custom" && (
            <>
              <label style={{ fontWeight: 600 }}>Nội dung HTML</label>
              <textarea
                rows="6"
                value={htmlContent}
                onChange={(e) => setHtmlContent(e.target.value)}
                placeholder="Nhập nội dung HTML..."
                style={{
                  width: "100%",
                  padding: "10px 12px",
                  marginTop: "8px",
                  marginBottom: "20px",
                  borderRadius: "8px",
                  border: "1px solid #ddd",
                }}
              />
            </>
          )}

          {/* TODO: Box danh sách email khi chọn group = user (sau này nối API /api/users) */}
          {group === "user" && (
            <div
              style={{
                marginTop: "8px",
                marginBottom: "20px",
                padding: "12px",
                borderRadius: "8px",
                background: "#fff8f2",
                border: "1px dashed #f0b9a7",
                fontSize: "14px",
                color: "#945b44",
              }}
            >
              📋 Sau này sẽ hiển thị danh sách email user ở đây (list gmail những tài khoản sẽ nhận).  
              Trước mắt mình gửi logic chạy ổn đã.
            </div>
          )}

          {/* BUTTON */}
          <button
            onClick={sendEmail}
            disabled={loading}
            style={{
              width: "100%",
              background: loading ? "#c4a4ad" : "#d86b7a",
              padding: "14px",
              borderRadius: "8px",
              color: "white",
              fontWeight: "bold",
              fontSize: "16px",
              cursor: loading ? "not-allowed" : "pointer",
              border: "none",
            }}
          >
            {loading ? "⏳ Đang gửi..." : "✉ Gửi Email"}
          </button>

          {/* RESULT MESSAGE */}
          {resultMsg && (
            <div
              style={{
                marginTop: "16px",
                padding: "12px",
                borderRadius: "8px",
                background:
                  resultMsg.type === "success" ? "#e8fff0" : "#ffe8e8",
                color: resultMsg.type === "success" ? "#008f3c" : "#d10000",
                fontSize: "14px",
              }}
            >
              {resultMsg.text}
            </div>
          )}
        </div>

        {/* RIGHT: PREVIEW */}
        <div
          style={{
            flex: 1,
            background: "#faf8f6",
            padding: "24px",
            borderRadius: "12px",
            border: "1px solid #f0e8e3",
          }}
        >
          <h2
            style={{
              fontSize: "20px",
              fontWeight: 600,
              marginBottom: "16px",
            }}
          >
            🔍 Preview
          </h2>

          <div
            style={{
              background: "white",
              padding: "20px",
              borderRadius: "10px",
              border: "1px solid #eee",
              minHeight: "200px",
            }}
            dangerouslySetInnerHTML={{ __html: htmlContent }}
          />
        </div>
      </div>
    </div>
  );
};

export default SendEmailPage;
